import { Output } from 'jsrepo/outputs';
import path from 'node:path';
import fs from 'node:fs';
import { writeFileIfChanged } from '../utils';

export default function (): Output {
	return {
		output: async (_buildResult, { cwd }) => {
			const filePath = path.join(cwd, 'src/lib/demos/index.ts');
			const demosDir = path.join(cwd, 'src/lib/demos');

			const demoNames = fs
				.readdirSync(demosDir)
				.filter((f) => f.endsWith('.svelte'))
				.map((f) => path.parse(f).name)
				.sort();

			const fileContent = `/**
* This file is automatically generated by jsrepo.
* Do not edit this file manually.
*/

export const DEMOS = [
    ${demoNames.map((demo) => `\t'${demo}'`).join(',\n')}
] as const;

export type Demo = (typeof DEMOS)[number];
`;

			writeFileIfChanged(filePath, fileContent);
		},
		clean: async () => {}
	};
}
